// インターフェースの定義
public interface MyInterface {
    void myMethod();
}

// クラスにインターフェースを実装する
public class MyClass1 implements MyInterface {
    // インターフェースで定義されたメソッドを実装する
    public void myMethod() {
        System.out.println("MyClass1's implementation of myMethod");
    }
}

public class MyClass2 implements MyInterface {
    // インターフェースで定義されたメソッドを実装する
    public void myMethod() {
        System.out.println("MyClass2's implementation of myMethod");
    }
}

// 多態性の例
public class Main {
    public static void main(String[] args) {
        // MyInterfaceの参照を使用して、異なる具体的なクラスのインスタンスを同じ方法で扱うことができる
        MyInterface obj1 = new MyClass1();
        MyInterface obj2 = new MyClass2();

        obj1.myMethod(); // MyClass1's implementation of myMethod
        obj2.myMethod(); // MyClass2's implementation of myMethod
    }
}

// インターフェースの定義
public interface MyInterface {
    void myMethod();

    // デフォルトメソッドの定義
    default void myDefaultMethod() {
        System.out.println("My Default Method");
    }
}

// クラスにインターフェースを実装する
public class MyClass implements MyInterface {
    // インターフェースで定義されたメソッドを実装する
    public void myMethod() {
        System.out.println("My Method");
    }

    // デフォルトメソッドは、必要に応じてオーバーライドできます。オーバーライドしない場合、インターフェースの実装が使用されます。
}

// メインクラス
public class Main {
    public static void main(String[] args) {
        MyClass myClass = new MyClass();
        myClass.myMethod(); // My Method
        myClass.myDefaultMethod(); // My Default Method
    }
}

